class Solution:
    def validSequence(self, word1: str, word2: str) -> List[int]:
        n, m = len(word1), len(word2)
        pos = [-1] * 26
        ans = []
        diff_count = 0
        i = n - 1
        j = m - 1
        while j >= 0:
            while i >= 0 and (word1[i] != word2[j]):
                i -= 1
            if i < 0:
                return []
            ans.append(i)
            if word1[i] != word2[j]:
                diff_count += 1
            i -= 1
            j -= 1
        if diff_count > 1:
            return []
        return ans[::-1]
